class Solution {
    public long minimumCost(String s) {
        int n = s.length();
        int[] prefix = new int[n + 1];
        int[] suffix = new int[n + 1];
        for (int i = 0; i < n; i++) {
            prefix[i + 1] = prefix[i] + (s.charAt(i) == '0' ? 1 : 0);
            suffix[n - i - 1] = suffix[n - i] + (s.charAt(n - i - 1) == '0' ? 1 : 0);
        }
        long res = Long.MAX_VALUE;
        for (int i = 0; i <= n; i++) {
            res = Math.min(res, prefix[i] + suffix[i]);
        }
        return res;
    }
}
